import{_ as a,o as r,c as o,a3 as i}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse(`{"title":"4. Coverage","description":"","frontmatter":{"title":"4. Coverage","eba":"Children's Services Award 2010","topics":["preliminary"]},"headers":[],"relativePath":"ebas/childrens-services/application-operation/4-coverage.md","filePath":"ebas/childrens-services/application-operation/4-coverage.md"}`),t={name:"ebas/childrens-services/application-operation/4-coverage.md"};function n(s,e,c,l,d,h){return r(),o("div",null,[...e[0]||(e[0]=[i(`<h1 id="_4-coverage" tabindex="-1">4. Coverage <a class="header-anchor" href="#_4-coverage" aria-label="Permalink to &quot;4. Coverage&quot;">​</a></h1><ol><li><p>This award covers employers throughout Australia in the children&#39;s services and early childhood education industry and their employees in the classifications listed in Schedule B---Classification Structure, to the exclusion of any other modern award. The award does not cover employers whose primary functions are covered by the following awards:</p><pre><code>a.  the *Educational Services (Schools) General Staff Award
    2010*;

b.  the *Higher Education Industry---General Staff---Award
    2010*;

c.  the *Local Government Industry Award 2010*; or

d.  the *Social, Community, Home Care and Disability Services
    Industry Award 2010*.
</code></pre><ol><li><p>The award does not cover an employee excluded from award coverage by the Act.</p></li><li><p>The award does not cover employees who are covered by a modern enterprise award, or an enterprise instrument (within the meaning of the <em>Fair Work (Transitional Provisions and Consequential Amendments) Act 2009</em> (Cth)), or employers in relation to those employees.</p></li><li><p>The award does not cover employees who are covered by a State reference public sector modern award, or a State reference public sector transitional award (within the meaning of the <em>Fair Work (Transitional Provisions and Consequential Amendments) Act 2009</em> (Cth)), or employers in relation to those employees.</p></li><li><p>This award covers any employer which supplies labour on an on-hire basis in the industry set out in clause 4.1 in respect of on-hire employees in classifications covered by this award, and those on-hire employees, while engaged in the performance of work for a business in that industry. This subclause operates subject to the exclusions from coverage in this award.</p></li><li><p>This award covers employers which provide group training services for apprentices and trainees engaged in the industry and/or parts of industry set out at clause 4.1 and those apprentices and trainees engaged by a group training service hosted by a company to perform work at a location where the activities described herein are being performed. This subclause operates subject to the exclusions from coverage in this award.</p></li><li><p>Where an employer is covered by more than one award, an employee of that employer is covered by the award classification which is most appropriate to the work performed by the employee and to the environment in which the employee normally performs the work.</p></li></ol></li></ol><p>NOTE: Where there is no classification for a particular employee in this award it is possible that the employer and that employee are covered by an award with occupational coverage.</p><p>Plain language terms: who is covered, scope.</p>`,4)])])}const u=a(t,[["render",n]]);export{m as __pageData,u as default};
